class Solution:
    def findRepeatedDnaSequences(self, s: str):
        result = set()
        n = len(s)
        for i in range(n - 9):
            sub = s[i:i+10]
            for j in range(i + 1, n - 9):
                if s[j:j+10] == sub:
                    result.add(sub)
                    break
        return list(result)

