class Solution:
    def findRepeatedDnaSequences(self, s: str):
        seen = set()
        added = set()
        result = []
        for i in range(len(s) - 9):
            sub = s[i:i+10]
            if sub in seen and sub not in added:
                result.append(sub)
                added.add(sub)
            seen.add(sub)
        return result

