var findRepeatedDnaSequences = function(s) {
    const seen = new Set();
    const added = new Set();
    const result = [];
    for (let i = 0; i <= s.length - 10; i++) {
        const sub = s.substring(i, i + 10);
        if (seen.has(sub) && !added.has(sub)) {
            result.push(sub);
            added.add(sub);
        }
        seen.add(sub);
    }
    return result;
};
